#include <bits/stdc++.h>
using namespace std;
bool srn(int a){
	if(a%4==0&&a%100!=0){
		return true;
	}else if(a%100==0&&a%400==0){
		return true;
	}else{
		return 0;
	}
}
int n;
int main() {
	int x,y;
	cin>>x>>y;
	for(int i=x;i<=y;i++){
		if(srn(i)){
			n++;
		}
	}
	cout<<n<<"\n";
	for(int i=x;i<=y;i++){
		if(srn(i)){
			cout<<i<<" ";
		}
	}
	return 0;
}
